    fun testToSet() = runTest {
        assertEquals(setOf(42), flow.toSet())
        assertEquals(emptySet(), emptyFlow.toSet())
    }

    @Test
    fun testSharedFlowToListWithDestination() = runTest {
        // Create a SharedFlow and emit some values
        val sharedFlow = MutableSharedFlow<Int>()

        // Test the user's pattern: collect into a mutable list and cancel
        val acc = mutableListOf<Int>()

        @OptIn(ExperimentalCoroutinesApi::class)
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION") // Testing deprecated but fixed functionality
            sharedFlow.toList(acc)
        }

        // Emit some test values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        yield() // Allow emissions to be collected

        // Cancel the collection job
        job.cancel()

        // Verify that the values were correctly added to the destination list
        assertEquals(listOf(1, 2, 3), acc)
    }

    @Test 
    fun testSharedFlowToSetWithDestination() = runTest {
        // Test the same pattern for toSet
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableSetOf<Int>()

        @OptIn(ExperimentalCoroutinesApi::class)
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            @Suppress("DEPRECATION") // Testing deprecated but fixed functionality
            sharedFlow.toSet(acc)
        }

        // Emit some values including duplicates
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(2) // duplicate
        sharedFlow.emit(3)

        yield() // Allow emissions to be collected

        job.cancel()

        // Verify that duplicates were filtered and values added to destination
        assertEquals(setOf(1, 2, 3), acc)
    }
}"}

